create table dirkspzm32.s_qs_fauf (
    sid                  varchar2(2 char) default 01 not null enable,
    firma_nr             number(2, 0) not null enable,
    fa                   number(*, 5) not null enable,
    fa_ag                number(*, 0) not null enable,
    fa_ag_upos           number(*, 0) not null enable,
    res_ext_name         varchar2(30 char) not null enable,
    status               varchar2(3 char) not null enable,
    artikel              varchar2(30 char) not null enable,
    kunde_nr             varchar2(30 char),
    liefermenge          number(*, 3),
    mengeneinheit        varchar2(3 char),
    pruef_nummer         number(*, 5),
    qs_p1                varchar2(50 char),
    qs_p2                varchar2(50 char),
    qs_p3                varchar2(50 char),
    qs_p4                varchar2(50 char),
    qs_p5                varchar2(50 char),
    qs_p6                varchar2(50 char),
    qs_p7                varchar2(50 char),
    qs_p8                varchar2(50 char),
    qs_p9                varchar2(50 char),
    qs_p10               varchar2(50 char),
    laborstatus          varchar2(1 char) not null enable,
    labortext            varchar2(30 char) not null enable,
    fehler_code          number(*, 5),
    fehler_text          varchar2(2500 char),
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0)
);

alter table dirkspzm32.s_qs_fauf
    add constraint check_s_qs_fauf_status
        check ( status in ( 'N', 'U', 'UE', 'ERR' ) ) enable;

alter table dirkspzm32.s_qs_fauf
    add constraint pk_s_qs_fauf
        primary key ( fa,
                      fa_ag,
                      fa_ag_upos,
                      created_date,
                      firma_nr,
                      sid )
            using index enable;


